#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5, M = 1e6 + 5;
int n, m, ans = -2e9;
vector<int> e[M];
int in[N], topo[N], dp[N], out[N], In[N], val[N];

bool toposort()
{
	int t = 0;
	queue<int> q;
	for(int i = 1; i <= n; i++)
		if(!in[i]) q.push(i), dp[i] = 1;
	while(!q.empty())
	{
		int u = q.front();
		q.pop();
		topo[++t] = u;
		for(int v : e[u])
		{
			in[v]--;
			dp[v] = max(dp[v], dp[u] + 1);
			if(!in[v]) q.push(v);
		}
	}
	return t == n;
}

int main()
{
	cin >> n >> m;
	for(int i = 1; i <= m; i++)
	{
		int u, v;
		cin >> u >> v;
		e[u].push_back(v);
		in[v]++;
		In[v]++;
		out[u]++;
	}
	toposort();
	for(int i = 1; i <= n; i++)
	{
		cout << dp[i] << endl;
	}
	return 0;
}
